const now = new Date();
const prev = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() - 1, 1));
const period = prev.toISOString().slice(0, 7);
const runId = `qa-local-${period}-${now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}-${Math.random().toString(16).slice(2, 8)}`;
const contractText = [
  'Partner: Stampli',
  'Product: FX revenue share',
  'Billing anchor for FX share: Credit Complete Date',
  'Billing anchor for FX reversal: Refund Complete Date',
  'Markup rate: 2.58%',
  'Monthly minimum revenue: 10000 USD',
  'Supported currencies: USD, CAD, EUR, GBP',
  'Missing currency fallback: partner standard rate 2.00%',
  'Reversal treatment: subtract from AP total, not AR',
  'If the contract parse is missing required fields, flag the row for human review',
].join('\n');
const billingFeedRows = [
  { transactionId: 'app-1001', partner: 'Stampli', period, ccy: 'USD', amount: 1500, mapped: true, fee: 38.7, feeType: 'fx' },
  { transactionId: 'app-1002', partner: 'Stampli', period, ccy: 'USD', amount: 600, mapped: true, fee: 15.48, feeType: 'fx' },
  { transactionId: 'app-1003', partner: 'Stampli', period, ccy: 'JPY', amount: 100000, mapped: false, fee: 0, feeType: 'fx' }
];
const snowflakeRows = [
  { transactionId: 'app-1001', partner: 'Stampli', period, ccy: 'USD', amount: 1500, feeType: 'fx' },
  { transactionId: 'app-1002', partner: 'Stampli', period, ccy: 'USD', amount: 610, feeType: 'fx' },
  { transactionId: 'app-1004', partner: 'Stampli', period, ccy: 'USD', amount: 200, feeType: 'fx' }
];
const makerInvoice = {
  partner: 'Stampli',
  period,
  amount: 10000,
  direction: 'We Owe Partner',
  buckets: {
    ap: 10000,
    ar: 0
  },
  notes: ['Sample maker invoice for local QA testing only']
};
const zeroFeeCandidates = billingFeedRows.filter((row) => Number(row.fee || 0) <= 0 || row.mapped === false || !String(row.ccy || '').trim());
return [{
  json: {
    runId,
    period,
    partner: 'Stampli',
    contractText,
    billingFeedRows,
    snowflakeRows,
    makerInvoice,
    zeroFeeCandidates,
    openaiApiUrl: 'https://api.openai.com/v1/chat/completions',
    primaryModel: 'gpt-5.4',
    shadowModel: 'gpt-5.4-mini',
    reportDestinationPrefix: 's3://your-billing-bucket/reports/billing-qa/local-test/',
    note: 'This local harness uses OpenAI twice for the model comparison pass because Claude is not wired yet. Replace the shadow parser with Claude when credentials are available.'
  }
}];

