function parseJsonBlock(text) {
  const raw = String(text || '').trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  const body = start >= 0 && end >= start ? raw.slice(start, end + 1) : raw;
  try {
    return JSON.parse(body);
  } catch (error) {
    return { parseError: String(error), raw: body };
  }
}

const ctx = $('Build Local QA Context').first().json;
const content = $json.choices?.[0]?.message?.content ?? '';
const shadowParsed = parseJsonBlock(content);
return [{
  json: {
    ...ctx,
    shadowModelResponse: content,
    shadowParsed
  }
}];

function normalise(value) {
  if (Array.isArray(value)) {
    return [...new Set(value.map((item) => String(item).trim()).filter(Boolean).map((item) => item.toUpperCase()))].sort();
  }
  if (value === null || value === undefined) return '';
  if (typeof value === 'object') return JSON.stringify(value);
  return String(value).trim();
}

function round(value) {
  return Math.round((Number(value) || 0) * 100) / 100;
}

function parseableNumber(value) {
  const num = Number(value);
  return Number.isFinite(num) ? num : 0;
}

function calcInvoice(terms, rows) {
  const markup = parseableNumber(terms.markupRate);
  const fallback = parseableNumber(terms.missingCurrencyFallbackRate || terms.fallbackRate || terms.defaultFallbackRate || markup);
  const minimum = parseableNumber(terms.monthlyMinimumRevenue);
  const supported = new Set(normalise(terms.supportedCurrencies));
  const detailRows = [];
  let generatedRevenue = 0;

  for (const row of rows) {
    const currency = String(row.ccy || row.currency || '').trim().toUpperCase();
    const eligible = supported.has(currency);
    const rateUsed = eligible && markup > 0 ? markup : fallback;
    const fee = round(parseableNumber(row.amount) * rateUsed);
    generatedRevenue = round(generatedRevenue + fee);
    detailRows.push({
      transactionId: row.transactionId,
      currency,
      amount: parseableNumber(row.amount),
      eligible,
      rateUsed: round(rateUsed),
      fee
    });
  }

  const invoiceAmount = generatedRevenue < minimum ? minimum : generatedRevenue;
  return {
    generatedRevenue: round(generatedRevenue),
    invoiceAmount: round(invoiceAmount),
    minimumApplied: generatedRevenue < minimum,
    detailRows
  };
}

function diffTerms(primary, shadow) {
  const keys = ['partner', 'product', 'billingAnchor', 'reversalAnchor', 'feeModel', 'markupRate', 'monthlyMinimumRevenue', 'supportedCurrencies', 'missingCurrencyFallbackRate', 'reversalTreatment', 'missingFieldBehavior'];
  const diffs = [];
  for (const key of keys) {
    const left = normalise(primary?.[key]);
    const right = normalise(shadow?.[key]);
    if (left !== right) {
      diffs.push({ field: key, primary: left, shadow: right });
    }
  }
  return diffs;
}

const ctx = $('Extract Shadow Parse').first().json;
const primary = $('Extract Primary Parse').first().json.primaryParsed;
const shadow = ctx.shadowParsed;
const makerAmount = parseableNumber(ctx.makerInvoice?.amount);
const primaryCalc = calcInvoice(primary, ctx.billingFeedRows || []);
const shadowCalc = calcInvoice(shadow, ctx.billingFeedRows || []);
const termDiffs = diffTerms(primary, shadow);
const amountDiffs = [];
if (round(primaryCalc.invoiceAmount) !== round(shadowCalc.invoiceAmount)) {
  amountDiffs.push({ field: 'invoiceAmount', primary: primaryCalc.invoiceAmount, shadow: shadowCalc.invoiceAmount, delta: round(shadowCalc.invoiceAmount - primaryCalc.invoiceAmount) });
}
if (round(primaryCalc.invoiceAmount) !== round(makerAmount)) {
  amountDiffs.push({ field: 'makerVsPrimary', maker: makerAmount, primary: primaryCalc.invoiceAmount, delta: round(primaryCalc.invoiceAmount - makerAmount) });
}
if (round(shadowCalc.invoiceAmount) !== round(makerAmount)) {
  amountDiffs.push({ field: 'makerVsShadow', maker: makerAmount, shadow: shadowCalc.invoiceAmount, delta: round(shadowCalc.invoiceAmount - makerAmount) });
}
const passed = termDiffs.length === 0 && amountDiffs.length === 0;
return [{
  json: {
    ...ctx,
    primaryParsed: primary,
    primaryCalc,
    shadowCalc,
    llmTermDiffs: termDiffs,
    llmAmountDiffs: amountDiffs,
    llmPassed: passed,
    llmNotes: passed ? ['Primary and shadow parsers matched the maker amount.'] : ['Model parse or amount differences were detected.']
  }
}];

function round(value) {
  return Math.round((Number(value) || 0) * 100) / 100;
}

function totals(rows) {
  return rows.reduce((acc, row) => {
    acc.count += 1;
    acc.amount = round(acc.amount + Number(row.amount || 0));
    return acc;
  }, { count: 0, amount: 0 });
}

const ctx = $('Compare LLM Parses').first().json;
const billingRows = Array.isArray(ctx.billingFeedRows) ? ctx.billingFeedRows : [];
const snowflakeRows = Array.isArray(ctx.snowflakeRows) ? ctx.snowflakeRows : [];
const appById = new Map(billingRows.map((row) => [String(row.transactionId), row]));
const snowById = new Map(snowflakeRows.map((row) => [String(row.transactionId), row]));
const mismatches = [];

for (const row of billingRows) {
  const key = String(row.transactionId);
  const other = snowById.get(key);
  if (!other) {
    mismatches.push({ transactionId: key, issue: 'missing_in_snowflake', makerAmount: round(row.amount || 0), checkerAmount: null, delta: null });
    continue;
  }
  const amountDelta = round((Number(other.amount || 0)) - (Number(row.amount || 0)));
  if (Math.abs(amountDelta) > 0.01) {
    mismatches.push({ transactionId: key, issue: 'amount_mismatch', makerAmount: round(row.amount || 0), checkerAmount: round(other.amount || 0), delta: amountDelta });
  }
}
for (const row of snowflakeRows) {
  const key = String(row.transactionId);
  if (!appById.has(key)) {
    mismatches.push({ transactionId: key, issue: 'missing_in_billing_app', makerAmount: null, checkerAmount: round(row.amount || 0), delta: null });
  }
}

const billingTotals = totals(billingRows);
const snowflakeTotals = totals(snowflakeRows);
const dataPassed = mismatches.length === 0 && Math.abs(round(billingTotals.amount - snowflakeTotals.amount)) <= 0.01 && billingTotals.count === snowflakeTotals.count;
return [{
  json: {
    ...ctx,
    billingTotals,
    snowflakeTotals,
    dataMismatches: mismatches,
    dataPassed,
    dataNotes: dataPassed ? ['Billing feed and Snowflake matched for the sample period.'] : ['Row or amount mismatches were detected between billing feed and Snowflake.']
  }
}];

function round(value) {
  return Math.round((Number(value) || 0) * 100) / 100;
}

const ctx = $('Compare Billing Feed and Snowflake').first().json;
const terms = ctx.primaryParsed || {};
const supported = new Set((Array.isArray(terms.supportedCurrencies) ? terms.supportedCurrencies : []).map((item) => String(item).trim().toUpperCase()).filter(Boolean));
const fallbackRate = Number(terms.missingCurrencyFallbackRate || 0) || 0.02;
const zeroFeeRows = Array.isArray(ctx.zeroFeeCandidates) ? ctx.zeroFeeCandidates : [];
const exceptions = zeroFeeRows.map((row) => {
  const currency = String(row.ccy || row.currency || '').trim().toUpperCase();
  const missingCurrency = currency && !supported.has(currency);
  const missingMapping = row.mapped === false;
  const reason = missingCurrency ? `Currency ${currency} is not in the contract currency list` : (missingMapping ? 'Missing fee mapping' : 'Zero fee transaction');
  const suggestedAction = missingCurrency || missingMapping ? 'Apply partner standard rate and correct the missing mapping' : 'Review why this row produced no fee';
  const suggestedFee = round(Number(row.amount || 0) * fallbackRate);
  return {
    transactionId: row.transactionId,
    currency,
    amount: round(row.amount || 0),
    fee: round(row.fee || 0),
    reason,
    suggestedFallbackRate: round(fallbackRate),
    suggestedFee,
    suggestedAction
  };
});
const missingDataPassed = exceptions.length === 0;
return [{
  json: {
    ...ctx,
    missingDataExceptions: exceptions,
    missingDataPassed,
    missingDataNotes: missingDataPassed ? ['No zero-fee transactions were found.'] : ['At least one transaction produced no fee because a required field or mapping was missing.']
  }
}];

const ctx = $('Scan Missing Data').first().json;
const llmPassed = !!ctx.llmPassed;
const dataPassed = !!ctx.dataPassed;
const missingDataPassed = !!ctx.missingDataPassed;
const overallPassed = llmPassed && dataPassed && missingDataPassed;
const generatedAt = new Date().toISOString();
const summary = {
  overallPassed,
  llmPassed,
  dataPassed,
  missingDataPassed,
  issueCount: (ctx.llmTermDiffs?.length || 0) + (ctx.llmAmountDiffs?.length || 0) + (ctx.dataMismatches?.length || 0) + (ctx.missingDataExceptions?.length || 0)
};
return [{
  json: {
    runId: ctx.runId,
    generatedAt,
    period: ctx.period,
    partner: ctx.partner,
    summary,
    llmComparison: {
      passed: llmPassed,
      termDiffs: ctx.llmTermDiffs || [],
      amountDiffs: ctx.llmAmountDiffs || [],
      makerAmount: ctx.makerInvoice?.amount || 0,
      primaryCalc: ctx.primaryCalc || {},
      shadowCalc: ctx.shadowCalc || {}
    },
    dataComparison: {
      passed: dataPassed,
      billingTotals: ctx.billingTotals || {},
      snowflakeTotals: ctx.snowflakeTotals || {},
      mismatches: ctx.dataMismatches || []
    },
    missingDataScan: {
      passed: missingDataPassed,
      exceptions: ctx.missingDataExceptions || []
    },
    notes: [
      'This workflow is a local, runnable checker harness.',
      'Primary parse uses OpenAI with gpt-5.4.',
      'Shadow parse currently uses OpenAI with gpt-5.4-mini as a stand-in until Claude credentials are available.',
      'Transaction comparison uses embedded sample data until Snowflake is wired in.'
    ],
    nextAction: overallPassed ? 'Clear to release billing for the sample data.' : 'Review the exception report before approving billing.'
  }
}];
